const configured = process.env.DDISCOVER_GOOGLE_PLACES_QUERIES_JSON;
const fallbackQueries = [
  'night club in Dresden Germany',
  'bar with live music in Dresden Germany',
  'event venue nightlife Dresden Germany'
];

let queries = fallbackQueries;
if (configured && configured.trim()) {
  try {
    queries = JSON.parse(configured);
  } catch (error) {
    throw new Error(`DDISCOVER_GOOGLE_PLACES_QUERIES_JSON is not valid JSON: ${error.message}`);
  }
}

if (!Array.isArray(queries) || queries.length === 0) {
  throw new Error('No Google Places queries configured.');
}

return queries.map((textQuery) => ({ json: { textQuery } }));

const output = [];
for (const item of $input.all()) {
  if (!process.env.GOOGLE_PLACES_API_KEY) {
    throw new Error('GOOGLE_PLACES_API_KEY is required.');
  }

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://places.googleapis.com/v1/places:searchText',
    headers: {
      'content-type': 'application/json',
      'x-goog-api-key': process.env.GOOGLE_PLACES_API_KEY,
      'x-goog-fieldmask': 'places.id,places.displayName,places.formattedAddress,places.location,places.types,places.businessStatus,places.websiteUri,places.regularOpeningHours'
    },
    body: {
      textQuery: item.json.textQuery,
      languageCode: 'de',
      regionCode: 'DE',
      includedType: 'bar',
      locationBias: {
        circle: {
          center: { latitude: 51.0504, longitude: 13.7373 },
          radius: 12000
        }
      }
    },
    json: true,
    timeout: 30000
  });

  output.push({
    json: {
      textQuery: item.json.textQuery,
      places: response.places || []
    }
  });
}
return output;

function slugPart(value) {
  return String(value || '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

const seen = new Set();
const venues = [];
for (const item of $input.all()) {
  for (const place of item.json.places || []) {
    if (!place.id || seen.has(place.id)) continue;
    seen.add(place.id);
    const name = place.displayName?.text;
    if (!name) continue;
    venues.push({
      sourceKey: `google-place-${slugPart(place.id)}`,
      name,
      city: 'Dresden',
      category: 'nightlife',
      googlePlace: {
        placeId: place.id,
        name,
        formattedAddress: place.formattedAddress,
        websiteUri: place.websiteUri,
        businessStatus: place.businessStatus,
        types: place.types || [],
        latitude: place.location?.latitude,
        longitude: place.location?.longitude,
        regularOpeningHoursText: (place.regularOpeningHours?.weekdayDescriptions || []).join('\n') || undefined
      },
      evidenceSnippets: [`Google Places Text Search result for query: ${item.json.textQuery}`],
      warnings: [],
      confidence: 0.82
    });
  }
}

return [
  {
    json: {
      source: {
        sourceKey: 'google-places-dresden-nightlife-bootstrap',
        name: 'Google Places Dresden nightlife bootstrap',
        sourceType: 'google_places',
        fetchedAt: Date.now()
      },
      venues,
      events: []
    }
  }
];

const output = [];
for (const item of $input.all()) {
  if (!process.env.DDISCOVER_CONVEX_SITE_URL) {
    throw new Error('DDISCOVER_CONVEX_SITE_URL is required, for example https://your-deployment.convex.site');
  }
  if (!process.env.DDISCOVER_INGESTION_TOKEN) {
    throw new Error('DDISCOVER_INGESTION_TOKEN is required.');
  }

  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: `${process.env.DDISCOVER_CONVEX_SITE_URL.replace(/\/+$/, '')}/ingestion/candidates`,
    headers: {
      authorization: `Bearer ${process.env.DDISCOVER_INGESTION_TOKEN}`,
      'content-type': 'application/json'
    },
    body: item.json,
    json: true,
    timeout: 30000
  });

  output.push({
    json: {
      source: item.json.source,
      venueCount: item.json.venues.length,
      result
    }
  });
}
return output;
